def solve(challenges):
    if not isinstance(challenges, list):
        raise ValueError("Input must be a list of challenges.")

    for challenge in challenges:
        if not isinstance(challenge, dict):
            raise ValueError("Each challenge must be a dictionary.")
        if 'phase' not in challenge or 'duration' not in challenge:
            raise ValueError("Each challenge must have 'phase' and 'duration' keys.")
        if not isinstance(challenge['phase'], str) or not isinstance(challenge['duration'], (int, float)):
            raise ValueError("Invalid types for 'phase' or 'duration'.")

    # Core logic to transition challenges through their phases
    for challenge in challenges:
        if challenge['phase'] == 'open':
            challenge['phase'] = 'in_progress'
        elif challenge['phase'] == 'in_progress':
            challenge['phase'] = 'completed'
        elif challenge['phase'] == 'completed':
            challenge['phase'] = 'archived'
        else:
            raise ValueError(f"Unknown phase: {challenge['phase']}")

    return challenges
